DATE_FORMAT(t.due_date,'%Y-%m-%d') as dueDate,
sum(t.unrestricted) as unrestricted
FROM inventory_supply t
WHERE t.tenant_id = #{tenantId}
and t.material_code = #{materialCode}
and t.logical_plant_id = #{logicalPlantId}
and t.due_date >= #{startTime}
and t.due_date <= #{endTime}
and t.supply_type = 1
and t.unrestricted > 0
and t.deleted = 0
group by DATE_FORMAT(t.due_date,'%Y-%m-%d');

